// ── VerifyResult shape ───────────────────────────────────────

describe('VerifyResult', () => {
  test('pass result has exitCode 0 and empty stderr', () => {
    const result = makeResult({ status: 'pass', exitCode: 0, stderr: '' });
    expect(result.exitCode).toBe(0);
    expect(result.stderr).toBe('');
  });

  test('fail result has non-zero exitCode and stderr content', () => {
    const result = makeResult({
      status: 'fail',
      exitCode: 1,
      stderr: 'FAIL src/auth.test.ts\n  Expected true, received false',
    });
    expect(result.exitCode).toBe(1);
    expect(result.stderr).toContain('Expected true');
  });

  test('skipped result has exitCode -1 for missing test file', () => {
    const result = makeResult({
      status: 'skipped',
      exitCode: -1,
      stderr: 'Test file not found: /path/to/test.ts',
    });
    expect(result.status).toBe('skipped');
    expect(result.exitCode).toBe(-1);
  });

  test('durationSeconds is optional', () => {
    const result = makeResult({ durationSeconds: undefined });
    expect(result.durationSeconds).toBeUndefined();
  });
});
